from __future__ import annotations
import re
from dataclasses import dataclass, field
from typing import Literal

Tier = Literal["fast", "standard", "specialist", "fallback"]

@dataclass
class RoutingDecision:
    tier: Tier
    model: str
    reasons: list[str] = field(default_factory=list)


CODE_KEYWORDS = re.compile(
    r"\b(function|class|def |import |async |await |\{|}|=>|\[\]|<\/|<[a-z]+>)",
    re.IGNORECASE,
)
MATH_KEYWORDS = re.compile(
    r"\b(integral|derivative|matrix|eigenv|probability|theorem|proof|equation)",
    re.IGNORECASE,
)
TOOL_MARKERS = re.compile(
    r"\b(search|browse|execute|run|fetch|retrieve|query the|look up)",
    re.IGNORECASE,
)


def estimate_tokens(text: str) -> int:
    # ~4 characters per token on average for English
    return len(text) // 4


def route_request(prompt: str, sla_class: str = "interactive") -> RoutingDecision:
    """
    Classify a prompt and return the appropriate routing tier.

    sla_class: "realtime" | "interactive" | "batch"
    """
    reasons: list[str] = []
    token_estimate = estimate_tokens(prompt)

    # Fast path: short prompt, no tools, no domain complexity, non-batch
    if (
        token_estimate < 200
        and not TOOL_MARKERS.search(prompt)
        and not CODE_KEYWORDS.search(prompt)
        and not MATH_KEYWORDS.search(prompt)
        and sla_class in ("realtime", "interactive")
    ):
        reasons.append(f"short prompt ({token_estimate} tokens), no tool markers")
        return RoutingDecision(tier="fast", model="gpt-4o-mini", reasons=reasons)

    # Specialist path: code or math domain
    if CODE_KEYWORDS.search(prompt):
        reasons.append("code domain detected")
        return RoutingDecision(tier="specialist", model="gpt-4o", reasons=reasons)

    if MATH_KEYWORDS.search(prompt):
        reasons.append("math/science domain detected")
        return RoutingDecision(tier="specialist", model="gpt-4o", reasons=reasons)

    # Tool-use path: escalate to standard or fallback based on complexity
    if TOOL_MARKERS.search(prompt):
        reasons.append("tool-use markers detected")
        if token_estimate > 800:
            reasons.append(f"high token count ({token_estimate})")
            return RoutingDecision(tier="fallback", model="gpt-4o", reasons=reasons)
        return RoutingDecision(tier="standard", model="gpt-4o-mini", reasons=reasons)

    # Default: standard tier
    reasons.append("default standard tier")
    return RoutingDecision(tier="standard", model="gpt-4o-mini", reasons=reasons)


# Usage
if __name__ == "__main__":
    samples = [
        "What is the capital of France?",
        "Write a Python function to parse nested JSON and extract all leaf values.",
        "Search the web for recent breakthroughs in quantum error correction and summarise.",
        "Prove that the sum of angles in a Euclidean triangle equals 180 degrees.",
    ]
    for prompt in samples:
        decision = route_request(prompt)
        print(f"[{decision.tier:12s}] {decision.model:20s} | {prompt[:60]}")
        print(f"               reasons: {', '.join(decision.reasons)}\n")

# WRONG: routing purely on token count
def bad_route(prompt: str) -> str:
    if len(prompt) < 200:
        return "fast"
    return "standard"

# RIGHT: combine length with domain and complexity signals
def good_route(prompt: str) -> str:
    tokens = len(prompt) // 4
    has_code = bool(re.search(r'\bdef |\bclass |```', prompt))
    has_tool = bool(re.search(r'\bsearch|\bfetch|\brun', prompt, re.I))
    if tokens < 150 and not has_code and not has_tool:
        return "fast"
    if has_code:
        return "specialist"
    return "standard"
